fn resolve_advanced_faces(
    model: &mut Model,
    aid: AdvancedFaceId,
    attrs: &[Attribute],
    idmap: &BTreeMap<u64, AnyId>,
) {
    let bounds_v = match &attrs[1] {
        Attribute::List(l) => l
            .iter()
            .map(|e| FaceBoundRef::from_any(*idmap.get(&as_ref_id(e)).expect("ref")))
            .collect(),
        Attribute::Unset => Vec::new(),
        other => panic!("vec ref: {other:?}"),
    };
    let face_geometry_v = SurfaceRef::from_any(*idmap.get(&as_ref_id(&attrs[2])).expect("ref"));
    let it = &mut model.advanced_faces.items[aid.0];
    it.bounds = bounds_v;
    it.face_geometry = face_geometry_v;
}

